let ntdsHosts = DeviceProcessEvents | where Timestamp > ago(7d) | where FileName =~ "ntdsutil.exe" or InitiatingProcessFileName =~ "ntdsutil.exe" | where ProcessCommandLine has_any ("ifm","create full","ac i ntds","activate instance ntds") | project ntdsTime=Timestamp, DeviceId, DeviceName, ntdsCmd=ProcessCommandLine, ntdsUser=AccountName;
let exfilHosts = DeviceProcessEvents | where Timestamp > ago(7d) | where FileName in~ ("azcopy.exe","MEGAsync.exe","MEGAcmd.exe","MEGAcmdServer.exe","megacmdshell.exe","rclone.exe") or ProcessCommandLine has_any ("blob.core.windows.net","mega.nz","mega.co.nz","--remote","copy --recursive") | project exfilTime=Timestamp, DeviceId, DeviceName, exfilProc=FileName, exfilCmd=ProcessCommandLine, exfilUser=AccountName;
ntdsHosts | join kind=inner exfilHosts on DeviceId | where exfilTime between (ntdsTime .. ntdsTime + 24h) | project ntdsTime, exfilTime, DeviceName, ntdsUser, exfilUser, ntdsCmd, exfilProc, exfilCmd | sort by exfilTime desc

let window = 1h;
let psexec = DeviceProcessEvents | where Timestamp > ago(7d) | where FileName in~ ("psexec.exe","psexec64.exe") or ProcessCommandLine has_any ("-s -d -accepteula","\\\\") and InitiatingProcessFileName in~ ("psexec.exe","psexec64.exe") | project t1=Timestamp, DeviceId, DeviceName, psexecCmd=ProcessCommandLine, psexecUser=AccountName;
let tamper = DeviceProcessEvents | where Timestamp > ago(7d) | where (FileName in~ ("powershell.exe","pwsh.exe") and ProcessCommandLine has_any ("DisableRealtimeMonitoring","Add-MpPreference","ExclusionPath","ExclusionExtension","MAPSReporting 0","SubmitSamplesConsent 2")) | project t2=Timestamp, DeviceId, tamperCmd=ProcessCommandLine;
let schedOrSvc = DeviceProcessEvents | where Timestamp > ago(7d) | where (FileName =~ "schtasks.exe" and ProcessCommandLine has "/create" and ProcessCommandLine has_any ("/ru SYSTEM","/ru \"NT AUTHORITY\\SYSTEM\"")) or (FileName =~ "sc.exe" and ProcessCommandLine has_any ("create","start")) | project t3=Timestamp, DeviceId, persistCmd=ProcessCommandLine;
let payloadDrop = DeviceFileEvents | where Timestamp > ago(7d) | where ActionType == "FileCreated" | where FolderPath has_any ("\\ProgramData\\","\\Users\\Public\\","\\Windows\\Temp\\","C$\\") and FileName endswith ".exe" | project t4=Timestamp, DeviceId, dropPath=FolderPath, dropFile=FileName, dropSha=SHA256;
psexec
| join kind=inner tamper on DeviceId | where t2 between (t1 .. t1+window)
| join kind=inner schedOrSvc on DeviceId | where t3 between (t1 .. t1+window)
| join kind=leftouter payloadDrop on DeviceId | where isnull(t4) or t4 between (t1 .. t1+window)
| project t1, DeviceName, psexecUser, psexecCmd, tamperCmd, persistCmd, dropPath, dropFile, dropSha
| sort by t1 desc
